        return np.linalg.norm(to_pos - from_pos) / truck_speed

    def adjusted_waiting_penalty(arrive_time, window, time_now):
        # Increased penalty if the truck risks missing the end of the time window
        if arrive_time < window[0]:
            return (window[0] - arrive_time)
        elif arrive_time > window[1]:
