        return 0

    def shared_load_factor(customer_index):
        close_trucks = 0
        for truck_pos in all_truck_pos:
            if np.linalg.norm(truck_pos - unvisited_customers[customer_index]) < np.linalg.norm(cur_truck_pos - unvisited_customers[customer_index]):
                close_trucks += 1
        return close_trucks

    costs = []
    load_factors = []
    for i, customer_pos in enumerate(unvisited_customers):
        tt = travel_time(cur_truck_pos, customer_pos)
        arrival = current_time + tt
        wait_pen = adjusted_waiting_penalty(arrival, time_windows[i], current_time)
        total_time = tt + wait_pen
        costs.append(total_time)
        load_factors.append(shared_load_factor(i))

    scores = []
    for i, cost in enumerate(costs):
        if load_factors[i] > 0:  # if other trucks are closer
            score = cost * (1 + 0.5 / load_factors[i])  # reduce penalty as more trucks are closer
        else:
            score = cost
        scores.append(score)

    best_node = np.argmin(scores)

